'use client'
import { createMachine, useMachine, cn } from '@cascivo/core'
import type { TextareaHTMLAttributes } from 'react'
import styles from './textarea.module.css'

const machine = createMachine({
  initial: 'idle' as const,
  states: {
    idle: { on: { FOCUS: 'focused' } },
    focused: { on: { BLUR: 'idle' } },
  },
})

export interface TextareaProps extends TextareaHTMLAttributes<HTMLTextAreaElement> {
  label?: string
  hint?: string
  error?: string
  resize?: 'none' | 'vertical' | 'both'
}

export function Textarea({
  label,
  hint,
  error,
  resize = 'vertical',
  rows = 4,
  className,
  id,
  onFocus,
  onBlur,
  ...props
}: TextareaProps) {
  const [state, send] = useMachine(machine)
  const textareaId =
    id ?? (label ? `cascade-textarea-${label.toLowerCase().replace(/\s+/g, '-')}` : undefined)

  return (
    <div
      className={cn(styles['wrapper'], className)}
      data-state={error ? 'error' : state.value}
      data-resize={resize}
    >
      {label && (
        <label className={styles['label']} htmlFor={textareaId}>
          {label}
        </label>
      )}
      <textarea
        id={textareaId}
        rows={rows}
        aria-multiline="true"
        className={styles['textarea']}
        aria-invalid={error ? true : undefined}
        aria-describedby={error ? `${textareaId}-error` : hint ? `${textareaId}-hint` : undefined}
        onFocus={(e) => {
          send('FOCUS')
          onFocus?.(e)
        }}
        onBlur={(e) => {
          send('BLUR')
          onBlur?.(e)
        }}
        {...props}
      />
      {error && (
        <span id={`${textareaId}-error`} className={styles['error']} role="alert">
          {error}
        </span>
      )}
      {!error && hint && (
        <span id={`${textareaId}-hint`} className={styles['hint']}>
          {hint}
        </span>
      )}
    </div>
  )
}

@layer cascivo.component {
  .wrapper {
    display: flex;
    flex-direction: column;
    gap: var(--cascivo-space-1);

    &[data-resize='none'] .textarea {
      resize: none;
    }
    &[data-resize='vertical'] .textarea {
      resize: vertical;
    }
    &[data-resize='both'] .textarea {
      resize: both;
    }
  }

  .label {
    font-family: var(--cascivo-font-sans);
    font-size: var(--cascivo-text-sm);
    font-weight: var(--cascivo-font-medium);
    color: var(--cascivo-color-text);
    line-height: var(--cascivo-leading-snug);
  }

  .textarea {
    width: 100%;
    min-block-size: 4rem;
    padding-inline: var(--cascivo-space-4);
    padding-block: var(--cascivo-space-3);
    font-family: var(--cascivo-font-sans);
    font-size: var(--cascivo-text-sm);
    line-height: var(--cascivo-leading-normal);
    color: var(--cascivo-color-text);
    background-color: var(--cascivo-color-surface);
    border: 1px solid var(--cascivo-color-border);
    border-radius: var(--cascivo-radius-field);
    transition:
      border-color var(--cascivo-duration-150) var(--cascivo-ease-out),
      box-shadow var(--cascivo-duration-150) var(--cascivo-ease-out);
    outline: none;

    &::placeholder {
      color: var(--cascivo-color-text-muted);
    }

    &:hover:not(:disabled):not(:focus) {
      border-color: var(--cascivo-color-border-strong);
    }

    &:focus {
      border-color: var(--cascivo-color-accent);
      box-shadow: var(--cascivo-focus-ring);
    }

    &:disabled {
      opacity: 0.5;
      cursor: not-allowed;
      background-color: var(--cascivo-color-bg-subtle);
    }

    .wrapper[data-state='error'] & {
      border-color: var(--cascivo-color-destructive);

      &:focus {
        box-shadow: 0 0 0 3px rgb(from var(--cascivo-color-destructive) r g b / 0.3);
      }
    }
  }

  .error {
    font-family: var(--cascivo-font-sans);
    font-size: var(--cascivo-text-sm);
    color: var(--cascivo-color-destructive);
    line-height: var(--cascivo-leading-snug);
  }

  .hint {
    font-family: var(--cascivo-font-sans);
    font-size: var(--cascivo-text-sm);
    color: var(--cascivo-color-text-subtle);
    line-height: var(--cascivo-leading-snug);
  }

  /* Coarse-pointer touch targets — raise minimum to 44px, desktop density unchanged */
  @media (pointer: coarse) {
    .textarea {
      min-block-size: var(--cascivo-target-min-coarse, 2.75rem);
    }
  }
}

@media (forced-colors: active) {
  .textarea {
    border: 1px solid FieldText;
    color: FieldText;
    background-color: Field;
  }

  .textarea:focus {
    outline: 2px solid Highlight;
    outline-offset: 2px;
  }
}
